   const AppListPage = {
     apps: [],           // 原始数据
     filteredApps: [],   // 过滤后数据
     searchTerm: '',
     filterType: 'all',
     viewMode: 'grid',   // grid / list / compact

     async init() {
       this.loadViewMode();
       await this.loadData();
       this.bindEvents();
     },

     async loadData() {
       this.showLoading();
       try {
         this.apps = await BotAgentApi.listEnabled();
         this.applyFilters();
         this.render();
       } catch (error) {
         Toast.error('数据加载失败');
         this.showEmptyState();
       } finally {
         this.hideLoading();
       }
     }
   };
