2. 搜索过滤实现 (防抖 300ms):
   ```javascript
   const searchInput = document.getElementById('searchInput');
   searchInput.addEventListener('input', debounce((e) => {
     AppListPage.searchTerm = e.target.value.toLowerCase();
     AppListPage.applyFilters();
   }, 300));

   applyFilters() {
     this.filteredApps = this.apps.filter(app => {
       const matchSearch = app.agentName.toLowerCase().includes(this.searchTerm);
       const matchType = this.filterType === 'all' || app.type === this.filterType;
       return matchSearch && matchType;
     });
     this.render();
   }
   ```

