1. 页面初始化逻辑 (app-basic-info.js)：
   ```javascript
   const BasicInfoPage = {
     botUserId: null,
     originalData: null,
     hasChanges: false,

     async init() {
       this.botUserId = getQueryParams().botUserId;
       if (!this.botUserId) {
         Toast.error('缺少应用ID参数');
         window.location.href = 'app-list.html';
         return;
       }
       await this.loadData();
       this.bindEvents();
     },

     async loadData() {
       this.showLoading();
       try {
         const data = await BotAgentApi.get(this.botUserId);
         this.originalData = { ...data };
         this.fillForm(data);
       } catch (error) {
         Toast.error('加载数据失败');
       } finally {
         this.hideLoading();
       }
     }
   };
   ```

2. 表单数据填充：
   ```javascript
   fillForm(data) {
     document.getElementById('appName').value = data.agentName || '';
     document.getElementById('appDesc').value = data.description || '';
     document.getElementById('appId').value = data.botUserId || '';
     document.getElementById('publicKey').value = data.publicKey || '';
     this.renderTags(data.tags || []);
     this.updateCharCounts();
