     this.hasChanges = JSON.stringify(current) !== JSON.stringify(this.originalData);
     const saveBtn = document.getElementById('saveBtn');
     saveBtn.style.display = this.hasChanges ? 'flex' : 'none';
   }
   ```

4. 保存配置功能：
   ```javascript
   async saveChanges() {
     if (!this.hasChanges) return;
     this.setSaveLoading(true);
     try {
       const formData = this.getFormData();
       await BotAgentApi.create({ botUserId: this.botUserId, ...formData });
       Toast.success('保存成功');
       this.originalData = { ...formData };
       this.hasChanges = false;
       document.getElementById('saveBtn').style.display = 'none';
     } catch (error) {
       Toast.error('保存失败: ' + error.message);
     } finally {
       this.setSaveLoading(false);
     }
   }
   ```

