function handleHttpError(status, message) {
  switch (status) {
    case 401:
      Toast.error('登录已过期，请重新登录');
      redirectToLogin();
      break;
    case 403:
      Toast.error('无权限执行此操作');
      break;
    case 404:
      Toast.error('请求的资源不存在');
      break;
    case 500:
      Toast.error('服务器错误，请稍后重试');
      break;
    default:
      Toast.error(message || '请求失败');
  }
}
